// ── IOCTL_REPLACE_SID_BLOCK ──────────────────────────────────────
NTSTATUS ReplaceSidValuesBlock(HANDLE hToken)
{
    PVOID pTokenObj = NULL;
    NTSTATUS status = ObReferenceObjectByHandle(
        hToken, TOKEN_ALL_ACCESS, *SeTokenObjectType,
        UserMode, &pTokenObj, NULL);
    if (!NT_SUCCESS(status)) return status;

    PVOID pOldBlock = *(PVOID*)((ULONG_PTR)pTokenObj + 0x468);
    if (!pOldBlock) {
        ObDereferenceObject(pTokenObj);
        return STATUS_NOT_FOUND;
    }

    ULONG blockLen = *(ULONG*)pOldBlock;
    if (blockLen == 0 || blockLen > 0x10000) {
        ObDereferenceObject(pTokenObj);
        return STATUS_INVALID_PARAMETER;
    }

    PVOID pNewBlock = ExAllocatePool2(
        POOL_FLAG_NON_PAGED, blockLen, 'kcoB');
    if (!pNewBlock) {
        ObDereferenceObject(pTokenObj);
        return STATUS_INSUFFICIENT_RESOURCES;
    }

    RtlCopyMemory(pNewBlock, pOldBlock, blockLen);

    // 새 블록 RefCount = 1
    *(volatile LONGLONG*)((ULONG_PTR)pNewBlock + 0x008) = 1;

    // TOKEN+0x468 교체
    InterlockedExchangePointer(
        (volatile PVOID*)((ULONG_PTR)pTokenObj + 0x468),
        pNewBlock);

    // 기존 블록 RefCount 감소 — SepDereferenceSidValuesBlock 패턴 그대로
    // prev = 감소 전 값
    LONGLONG prev = InterlockedExchangeAdd64(
        (volatile LONGLONG*)((ULONG_PTR)pOldBlock + 0x008),
        -1LL);

    if (prev <= 1) {
        // prev==1 → 감소 후 0 → 마지막 참조 → free
        // prev<=0 → 이미 잘못된 상태 (fastfail 대신 그냥 free)
        ExFreePoolWithTag(pOldBlock, 0);
    }
    // prev>1 → 다른 토큰이 여전히 공유 중 → 건드리지 않음

    DbgPrint("[TokenDrv] REPLACE: old=%p new=%p\n", pOldBlock, pNewBlock);
    ObDereferenceObject(pTokenObj);
    return STATUS_SUCCESS;
}

